def sdiv_8(a, b):
    """Signed division with truncation toward zero, returning i8."""
    # Convert from unsigned to signed
    if a & 0x80:
        a_signed = a - 256
    else:
        a_signed = a

    # Truncation toward zero
    if a_signed < 0 and b > 0:
        result = -((-a_signed) // b)
    elif a_signed > 0 and b < 0:
        result = -(a_signed // (-b))
    else:
        result = a_signed // b

    # Convert back to unsigned 8-bit
    return result & 0xFF

def ashr_8(a, shift):
    """Arithmetic shift right, returning i8."""
    # Convert to signed
    if a & 0x80:
        a_signed = a - 256
    else:
        a_signed = a
    result = a_signed >> shift
    # Convert back to unsigned 8-bit
    return result & 0xFF

def sext_bool_to_i8(b):
    """Sign-extend boolean to i8."""
    return 0xFF if b else 0x00

